// A "children map" is a plain object that exists only to group siblings:
// no comp, no options, no LANGUAGES keys, and no ~-rooted tag strings among
// its values. When we encounter one inside an array child slot, we inline its
// values as siblings instead of wrapping them in a default <span>.
function isChildrenMap(obj) {
    if (!obj || typeof obj !== 'object' || Array.isArray(obj)) return false;
    if (obj.comp !== undefined || obj.options !== undefined) return false;
    const RESERVED = ['comp','options','header','footer','hOptions','hHeader','hFooter','output','switch','wrap','to','asChild'];
    for (const k of Object.keys(obj)) {
        if (RESERVED.includes(k)) return false;
        const v = obj[k];
        if (typeof v === 'string' && v.startsWith('<') && v.endsWith('>') && v.includes('~')) return false;
    }
    return Object.keys(obj).length > 0;
}

export function renderArray(self, el, h_) {
    let main;

    if (
        typeof el?.[0] === "string" &&
        el?.[0]?.startsWith("<") &&
        el?.[0]?.endsWith(">")
    ) {
        let theTag;
        let theOptions;
        let theLink;

        let theTagSlip = el?.[0].replace("<", "").replace(">", "").split(",");

        theTag = theTagSlip?.[0].replace("<", "").replace(">", "");

        theOptions = self.strToObj(theTagSlip?.[1]);
        theLink = self.strToObj(theTagSlip?.[2]);

        if (!self.isNonEmpty(theOptions)) {
            theOptions = {};
        } else if (typeof theOptions == "string") {
            theOptions = { class: theOptions };
        }

        if (theLink) {
            theOptions.to = theLink;
        }

        let e = {
            comp: theTag,
            options: theOptions,
        };

        if (el?.[0]?.includes("~")) {
            // Separate direct children (before next <tag>) from sub-array items
            let directChildren = [];
            let subItems = null;
            if (el.length > 1) {
                let subStart = el.length; // default: no sub-tag found
                for (let i = 1; i < el.length; i++) {
                    if (typeof el[i] === 'string' && el[i].startsWith('<') && el[i].endsWith('>')) {
                        subStart = i;
                        break;
                    }
                }
                // Items between the wrapper tag and the next <tag> are direct children
                for (let i = 1; i < subStart; i++) {
                    let item = el[i];
                    if (typeof item === 'string' && !item.startsWith('<') && !item.startsWith('./') && !item.includes('|') && !item.includes('__')) {
                        directChildren.push(item);
                    } else if (isChildrenMap(item)) {
                        for (const k of Object.keys(item)) {
                            directChildren.push(self.toWBC_(item[k], h_));
                        }
                    } else {
                        directChildren.push(self.toWBC_(item, h_));
                    }
                }
                if (subStart < el.length) {
                    subItems = el.slice(subStart);
                }
            }
            main = h_(
                theTag.replace("~", ""),
                {
                    ...(theOptions || {}),
                    ref: "rawHtml",
                    attrs: { href: theLink },
                },
                [
                    ...directChildren,
                    subItems ? self.toWBC_(subItems, h_) : null,
                ]
            );
        } else {
            let cleanTag = theTag.replace("<", "").replace(">", "");
            main = el.slice(1).map((item, i) => {
                if (typeof item === 'string' && !item.startsWith('<') && !item.startsWith('./') && !item.includes('|') && !item.includes('__')) {
                    // Simple text: render directly into the tag to avoid WBHtml span wrappers
                    return h_(cleanTag, theOptions || {}, [item]);
                }
                if (Array.isArray(item)) {
                    // Nested array: flatten items as direct children of the parent tag (Case C)
                    let children = item.map((child) => {
                        if (typeof child === 'string' && !child.startsWith('<') && !child.startsWith('./') && !child.includes('|') && !child.includes('__')) {
                            return child;
                        }
                        return self.toWBC_(child, h_);
                    });
                    return h_(cleanTag, theOptions || {}, children);
                }
                if (isChildrenMap(item)) {
                    // Plain children-map: inline its values as siblings inside the tag
                    let children = Object.keys(item).map((k) => {
                        const child = item[k];
                        if (typeof child === 'string' && !child.startsWith('<') && !child.startsWith('./') && !child.includes('|') && !child.includes('__')) {
                            return child;
                        }
                        return self.toWBC_(child, h_);
                    });
                    return h_(cleanTag, theOptions || {}, children);
                }
                return self.toWBC_(e, h_, item);
            });
        }

    } else if (
        (typeof el?.[0]?.comp == "string" &&
            (el?.[0]?.comp?.includes("~") ||
                el?.[0]?.comp?.includes("*") ||
                (el?.[0]?.comp?.startsWith("<") &&
                    el?.[0]?.comp?.endsWith(">")))) ||
        (["nested", "inherit", "adjacent"].includes(
            el?.[0]?.options?.disposition
        ) &&
            el?.[0]?.options?.hide)
    ) {

        let newArr = [];
        let el0 = self.clone(el?.[0]);

        if (
            el?.[0]?.options?.disposition == "nested" ||
            el?.[0]?.comp?.includes("~")
        ) {
            let theTag = el[0].comp
                .replace("<", "")
                .replace(">", "")
                .replace("~", "");

            el[0].options.footers = el.length > 1 ? el.slice(1) : null;
            newArr = h_('WBC', { props: { item: el[0], class: "brown" } });

        } else if (
            el?.[0]?.options?.disposition == "inherit" ||
            el0?.comp?.includes("*")
        ) {
            el.slice(1).forEach((item, i) => {
                if (self.isPlainObject(item)) {
                    let e = self.mergeObjects(el0, item);
                    newArr.push(
                        h_("WBC", {
                            keyy: `wbc-key-arr-${i}-${self.computedKey}`,
                            props: { item: e },
                        })
                    );
                } else {
                    let e0 = {
                        ...el0,
                        options: {
                            ...(el0?.options || {}),
                        },
                    };

                    e0.options.html = [e0?.options?.html, item];

                    e0.comp = e0.comp
                        .replace("*", "")
                        .replace("<", "")
                        .replace(">", "");

                    newArr.push(
                        h_("WBC", {
                            keyy: `wbc-key-arr-${self.computedKey}`,
                            props: { item: e0 },
                        })
                    );
                }
            });
        } else if (
            el?.[0]?.options?.disposition == "adjacent" ||
            (el?.[0]?.comp?.startsWith("<") && el?.[0]?.comp?.endsWith(">"))
        ) {
            newArr = el.slice(1).map((item, i) => {
                return self.toWBC_(el0, h_, item);
            });
        }

        main = newArr;

    } else {
        let v0 = h_("WBC", {
            ref: "rawHtml",
            keyy: `wbc-child-${self.computedKey}`,
            props: { item: el[0] },
        });

        main = [v0, self.toWBC_(el.length > 0 ? el.slice(1) : null, h_)];
    }

    return main;
}
