/**
 * utils/auth.js
 * HMAC-based cookie signing and verification for _wb_core_auth.
 * Prevents cookie forgery and removes customer PII from client-side storage.
 */

const AUTH_SECRET = 'wbc-core-auth-v2';
const COOKIE_NAME = '_wb_core_auth';
const COOKIE_MAX_AGE = 86400; // 24 hours in seconds

/**
 * Read the _wb_core_auth cookie value (raw parsed JSON).
 * Returns null if cookie not found, expired, or structurally invalid.
 */
export function readAuthCookie() {
    try {
        const match = document.cookie.match(new RegExp(`(?:^|; )${COOKIE_NAME}=([^;]*)`));
        if (!match || !match[1]) return null;
        const data = JSON.parse(decodeURIComponent(match[1]));
        return data;
    } catch (e) {
        return null;
    }
}

/**
 * Verify the _wb_core_auth cookie integrity using HMAC-SHA256.
 * Returns the payload (without hmac) if valid, null otherwise.
 * Async because it uses Web Crypto API.
 */
export async function verifyAuthCookie() {
    const data = readAuthCookie();
    if (!data) return null;

    // Enforce new HMAC-signed format
    if (!data.hmac || !data.status || !data.ts) return null;

    const payload = { status: data.status, ts: data.ts };

    try {
        const expectedHmac = await computeHmac(payload, AUTH_SECRET);
        if (data.hmac !== expectedHmac) return null;
    } catch (e) {
        return null;
    }

    // Check expiry (24 hours)
    if (Date.now() - data.ts >= 86400000) return null;

    return payload;
}

/**
 * Synchronous structural check — used at store init time
 * where async crypto is not available. Returns true if the
 * cookie has the HMAC field and appears structurally valid.
 * Full HMAC verification happens later in the lifecycle hook.
 */
export function checkAuthCookieSync() {
    const data = readAuthCookie();
    if (!data) return null;

    // New format requires hmac field
    if (!data.hmac || !data.status || !data.ts) return null;
    if (data.status !== 'valid') return null;
    if (Date.now() - data.ts >= 86400000) return null;

    // Structural check passed — return details for store hydration
    return data.details || { validated: true };
}

/**
 * Sign auth payload with HMAC-SHA256 and write to cookie.
 * Removes customer details — only stores status + timestamp + hmac.
 */
export async function signAndSetAuthCookie(status, details) {
    if (!status) return;

    const payload = { status, ts: Date.now() };
    const hmac = await computeHmac(payload, AUTH_SECRET);

    const cookieData = JSON.stringify({ ...payload, hmac });
    document.cookie = `${COOKIE_NAME}=${encodeURIComponent(cookieData)}; path=/; max-age=${COOKIE_MAX_AGE}; SameSite=Lax`;
}

/**
 * Clear the auth cookie.
 */
export function clearAuthCookie() {
    document.cookie = `${COOKIE_NAME}=; path=/; max-age=0; SameSite=Lax`;
}

/**
 * Compute HMAC-SHA256 signature using Web Crypto API.
 */
async function computeHmac(payload, secret) {
    const enc = new TextEncoder();
    const keyData = enc.encode(secret);
    const cryptoKey = await crypto.subtle.importKey(
        'raw',
        keyData,
        { name: 'HMAC', hash: 'SHA-256' },
        false,
        ['sign']
    );
    const signature = await crypto.subtle.sign(
        'HMAC',
        cryptoKey,
        enc.encode(JSON.stringify(payload))
    );
    return btoa(String.fromCharCode(...new Uint8Array(signature)));
}
