// packages/wb-core/src/core/dragHandler.js
// Extracted drag handler methods from WBC.js (task 2.6)
// Self-contained state: uses component reactive data (draggable, dragStartX/Y, offsetX/Y)

/**
 * Mixin providing drag-and-drop functionality for floating/focus containers.
 * Manages mousedown/mousemove/mouseup event handlers for dragging.
 */
export const wbDragMixin = {
    methods: {
        startDrag(event) {
            this.draggable = true;
            this.dragStartX = event.clientX - this.offsetX;
            this.dragStartY = event.clientY - this.offsetY;
            document.addEventListener("mousemove", this.doDrag);
            document.addEventListener("mouseup", this.endDrag);
            event.preventDefault();
        },
        doDrag(event) {
            if (this.draggable) {
                this.offsetX = event.clientX - this.dragStartX;
                this.offsetY = event.clientY - this.dragStartY;
            }
        },
        endDrag() {
            this.draggable = false;
            document.removeEventListener("mousemove", this.doDrag);
            document.removeEventListener("mouseup", this.endDrag);
        },
    }
};