/**
 * Decorator: Flatten arrays of VNodes/Elements into a span
 */
export function applyArrayFlattener(self, h, finalRender) {
    if (Array.isArray(finalRender)) {
        return h(
            "span",
            finalRender
                .filter((e) => e)
                .map((e) => {
                    return e?.$el?.children || e;
                })
        );
    }
    return finalRender;
}
