/*
 * Calculates nesting depth of complex object structures.
 * Extracted from utils.js to break the monolith.
 */
export function getObjectDepth(obj, visited = new WeakSet()) {
    if (
        obj === null ||
        typeof obj !== "object" ||
        obj instanceof Function
    ) {
        return 0;
    }

    // Guard against circular structures and internal Vue instances
    if (
        obj._isVue ||
        obj.$options ||
        obj.__v_isVNode ||
        visited.has(obj)
    ) {
        return 0;
    }

    visited.add(obj);

    let maxDepth = 0;
    for (const key in obj) {
        if (Object.prototype.hasOwnProperty.call(obj, key)) {
            const depth = getObjectDepth(obj[key], visited);
            maxDepth = Math.max(maxDepth, depth);
        }
    }

    return maxDepth + 1;
}
