/**
 * renderers/renderMissingComponentWarning.js
 * Renders a warning VNode when a sub-package component is not registered.
 */

/**
 * Returns a styled warning VNode for a missing sub-package component.
 * @param {string} compName - The component tag name (e.g. 'WBMermaid', 'WBCode')
 * @param {Function} h - The createElement / render function
 * @returns {VNode} A styled div indicating the missing registration
 */
export function renderMissingComponentWarning(compName, h) {
    const pkgName = compName.replace(/^WB/, 'wb-').toLowerCase();
    const label = `#${compName}Missing: "${pkgName}" not registered`;

    console.error(`[WBC-UI2] ${compName} is not registered. Install the "${pkgName}" sub-package.`);

    return h(
        "div",
        {
            style: {
                backgroundColor: "#F8F9FA",
                color: "red",
                width: "100%",
                height: "100%",
                margin: "10px",
            },
        },
        [label]
    );
}
