import { LANGUAGES } from '../constants';
import { renderMissingComponentWarning } from './renderMissingComponentWarning.js';
import { COMPONENT_STRATEGIES, renderSlots } from './componentStrategies.js';
import { applyMenuWrapper } from './menuHandler.js';
import { renderScopedArray, KEYS_TO_AVOID } from './scopeRenderer.js';
import Vue from 'vue'; // imported to resolve Vue.component
// If wbcObj is needed, we will pass it via self or context, but there's a Vue.component call.

export function renderObject(self, el, h_, context) {
    let { 
        externalChildren, insideHeadersVN, insideFootersVN, 
        globalHeaderVN, globalFooterVN, externalWrapperObj, 
        extChildren, __DEV__, wbcObj 
    } = context;
    let main;
    let options;
    let comp;
    let raw0;

                // Pre-process plain objects whose values form a <tag> array pattern
                // to avoid an extra WBC instance and its applyArrayFlattener <span> wrapper
                if (
                    externalChildren &&
                    typeof externalChildren === 'object' &&
                    !Array.isArray(externalChildren) &&
                    !self.isVnode(externalChildren)
                ) {
                    let ecValues = Object.keys(externalChildren).sort().map(k => externalChildren[k]);
                    if (
                        ecValues.length > 0 &&
                        typeof ecValues[0] === 'string' &&
                        ecValues[0].startsWith('<') &&
                        ecValues[0].endsWith('>')
                    ) {
                        extChildren = self.toWBC_(ecValues, h_);
                    } else {
                        extChildren = h_("WBC", {
                            key: `wbc-ext-child-${self.computedKey}`,
                            props: { item: externalChildren },
                        });
                    }
                } else {
                    extChildren = h_("WBC", {
                        key: `wbc-ext-child-${self.computedKey}`,
                        props: { item: externalChildren },
                    });
                }

                options = self._wbcOptions(el);
                comp = self.comp(el);

                //#############//

                let InputLikeComponent = [
                    "input",
                    "checbox",
                    "radio",
                    "select",
                    "textarea",
                    "VTextField",
                    "VCheckbox",
                    "VTextarea",
                    "VSelect",
                    "VRadio",
                    "VSlider",
                    "VRangeSlider",
                    "VSwitch",
                    "VAutocomplete",
                    "VDatePicker",
                    "VColorPicker",
                    "VMenu",
                    "VRadioGroup",
                    "vTimePicker",
                ];

                if (InputLikeComponent.includes(comp)) {

                    self.itemListeners.input = (v) => {

                        self.internalValue = v;

                        self.internalValueIsValid = self?.$refs[self.refName]?.validate(
                            true,
                            v
                        );

                    };

                }

                // 	////////////////////V-Model alernative: initialisons events ///////////////////////

                /////////////////////////////////////////

                ////////////////////////////////////////////////////
                /////////////maniputation of main el ////////////////
                ////////////////////////////////////////////////////



                if (options?.hide || self.hide) {
                    main = null;
                }
                else if (
                    Object.keys(el).length > 0 &&
                    LANGUAGES.some((e) => Object.keys(el).includes(e))
                ) {
                    main = h_("WBHtml", {
                        ref: "rawHtml",

                        key: `wbhtml-key-${self.computedKey}-${el.length}`,
                        props: {
                            html: el,
                        },
                    });
                } else if (Object.keys(el).length > 0 && !el?.comp) {

                    let theHtml = [];
                    let newObj1 = {
                        comp: el?.options?.comp || "span",
                        options: { ...(el?.options || {}) /* ,disposition:'nested' */ },
                    };

                    delete newObj1?.options?.float
                    delete newObj1?.options?.drag
                    delete newObj1?.options?.close

                    let wrapObj = el?.options?.wrap;

                    let keyToAvoid = KEYS_TO_AVOID;

                    Object.keys(el)
                        .sort()
                        .forEach((key) => {

                            if (!keyToAvoid.has(key)) {
                                theHtml.push(el[key]);

                            }

                        });

                    if (wrapObj) {
                        newObj1.comp = wrapObj?.options?.wrap?.comp || newObj1.comp;
                        newObj1.options = {
                            ...(newObj1?.options?.wrap?.options || {}),
                            ...(newObj1?.options || {}),
                        };

                        delete newObj1.options.wrap;

                    }

                    // Scope-based rendering — delegate to extracted handler
                    const scopeResult = renderScopedArray(self, h_, theHtml, el);
                    if (scopeResult !== null) {
                        main = scopeResult;
                    } else {
                        main = self.toWBC_(newObj1, h_, theHtml);
                    }

                } else if (
                    Array.isArray(comp)) {

                    let newArr = self.resolveValuesWithSource(comp, el)

                    if (el?.header) { newArr.header = el?.header }
                    if (el?.footer) { newArr.footer = el?.footer }
                    if (el?.output) { newArr.output = el?.output }
                    if (el?.options) { newArr.options = el?.options }
                    if (el?.hOptions) { newArr.hOptions = el?.hOptions }
                    if (el?.switch) { newArr.switch = el?.switch }
                    if (el?.footer) { newArr.footer = el?.footer }
                    if (el?.header) { newArr.header = el?.header }
                    if (el?.hFooter) { newArr.hFooter = el?.hFooter }
                    if (el?.header) { newArr.header = el?.header }
                    if (el?.hHeader) { newArr.hHeader = el?.hHeader }
                    if (el?.fStyle) { newArr.fStyle = el?.fStyle }
                    if (el?.dive) { newArr.dive = el?.dive }
                    if (el?.update) { newArr.update = el?.update }
                    if (el?.init) { newArr.init = el?.init }
                    if (el?.init0) { newArr.init0 = el?.init0 }
                    if (el?.tracker) { newArr.tracker = el?.tracker }
                    if (el?.watch) { newArr.watch = el?.watch }
                    if (el?.forward) { newArr.forward = el?.forward }

                    main = h_("WBC", {
                        ref: "arrHtml",
                        key: `wbc-flat-arr-${(newArr.length || 0) % 1000}`,
                        props: { item: newArr },
                    });

                } else if (typeof (comp) == 'object' && !(
                    comp.install ||
                    comp.setup ||
                    comp._isVue ||
                    comp.$options ||
                    comp.__v_isVNode ||
                    comp._scope ||
                    comp._effects ||
                    comp.vm
                )) {

                    const promotedKeys = ['options', 'header', 'footer', 'hOptions', 'hHeader', 'hFooter'];
                    const compForResolve = { ...comp };
                    for (const k of promotedKeys) delete compForResolve[k];

                    let newObj = self.resolveValuesWithSource(compForResolve, el)

                    for (const k of promotedKeys) {
                        if (comp[k] !== undefined) {
                            newObj[k] = comp[k];
                        } else if (el?.[k] !== undefined) {
                            newObj[k] = el[k];
                        }
                    }

                    if (el?.output) { newObj.output = el?.output }
                    if (el?.switch) { newObj.switch = el?.switch }
                    if (el?.fStyle) { newObj.fStyle = el?.fStyle }
                    if (el?.dive) { newObj.dive = el?.dive }
                    if (el?.update) { newObj.update = el?.update }
                    if (el?.init) { newObj.init = el?.init }
                    if (el?.init0) { newObj.init0 = el?.init0 }
                    if (el?.tracker) { newObj.tracker = el?.tracker }
                    if (el?.watch) { newObj.watch = el?.watch }
                    if (el?.forward) { newObj.forward = el?.forward }

                    if (!newObj.options) newObj.options = {};

                    main = h_("WBC", {
                        ref: "arrHtml",
                        ...options,
                        props: { item: newObj },
                    });

                } else if (
                    (typeof comp == "string" &&
                        (comp.includes("|") || comp.includes("+")))
                ) {

                    if (
                        typeof comp == "string" &&
                        (comp.includes("|") || comp.includes("+"))
                    ) {
                        comp = self.strToComps(comp);
                    }

                    let newArr = [];

                    comp.forEach((key, i) => {
                        let itemObj = {};

                        if (typeof key == "string") {
                            itemObj =
                                el?.[key.replace("~", "")] ||
                                `<${key.replace("<", "").replace(">", "")}>`;

                        } else if (Array.isArray(key)) {

                            let keyArrObj = {
                                comp: key,
                            };

                            self.flattenArray(key).forEach((k) => {
                                if (Object.keys(el).includes(k)) {
                                    keyArrObj[k] = el[k];
                                }
                            });

                            itemObj = h_("WBC", {
                                key: `wbc-flat-arr-${self.computedKey}`,
                                props: { item: keyArrObj },
                            });

                        } else {
                            itemObj = key;
                        }

                        newArr.push(itemObj);
                    });

                    main = h_("WBC", {
                        ref: "arrHtml",
                        key: `wbc-flat-arr-${self.computedKey}`,
                        props: { item: newArr },
                    });

                    // 			// Handle import errors here

                } else if (typeof comp === "string" && comp?.startsWith("./")) {
                    let compOpt = {
                        mainContent: h_("WBC", {
                            ...(options || {}),
                            props: { props: options?.props || {}, item: comp },
                        }),
                        options: {
                            ...(options || {}),
                        },
                    };
                    main = h_("WBC", { props: { item: compOpt } });

                } else if (typeof comp === "function" && comp.length == 0) {
                    let theComp = comp;
                    theComp()
                        .then((e) => {
                            let wb = e?.default || e?.name || {};
                            Vue.component(wb.name, wb);

                            wbcObj.components[wb.name] = wb;
                            comp = wb.name;
                            if (typeof options === 'object' && options !== null) {
                                options.props = {
                                    ...(wb.props || {}),
                                    ...options.props,
                                };
                            }
                        })
                        .catch((error) => {
                            // Handle import errors here

                        });

                } else {
                    let innerHtml;
                    let elHtml;

                    let hInnerHtml;

                    let html = self.html(el);

                    if (
                        typeof options?.html ==
                        "object" /* && (options?.html.comp||options?.html.hComp) */ ||
                        typeof options?.html == "function" ||
                        options?.html?.startsWith("https://") ||
                        options?.html?.startsWith("http://") ||
                        options?.html?.startsWith("/") ||
                        options?.html?.startsWith("./") ||
                        options?.html?.startsWith("../") ||
                        self.isVnode(options?.html) ||
                        ["VSpacer", "VDivider"].includes(options?.html)
                    ) {
                        innerHtml = h_("WBC", {
                            key: `wbc-key-inner-html-${self.computedKey}`,
                            props: { item: html },
                        });

                    } else {
                        elHtml = html;

                        // Skip empty WBHtml to avoid rendering empty <span> wrappers
                        innerHtml = self.isNonEmpty(elHtml) ? h_("WBHtml", {
                            key: `wbhtml-key-${elHtml?.length}-${self.computedKey}`,

                            props: {
                                html: elHtml,
                            },
                        }) : null;
                    }
                    // Strategy pattern — delegate to component-specific renderer
                    const strategy = COMPONENT_STRATEGIES[comp];
                    if (strategy) {
                        main = strategy(self, h_, el, options, innerHtml, {
                            insideHeadersVN, insideFootersVN, extChildren
                        });
                    }

                    else {
                        raw0 = h_(
                            comp,
                            {
                                ref: "rawHtml",
                                ...options,

                                on: self.itemListeners,
                                key: `key-raw0-${self.computedKey}`,
                            },
                            [
                                el?.switch === true
                                    ? hInnerHtml?.children || hInnerHtml
                                    : innerHtml?.children || innerHtml,

                                ...renderSlots(self, h_, options),

                                // footers
                            ]
                        );

                        self.vNodes.raw0 = raw0;

                        main = h_(
                            comp,
                            {

                                ...options,

                                on: self.itemListeners,
                                // attrs: self.attrs

                            },
                            [

                                insideHeadersVN,
                                innerHtml?.children || innerHtml,

                                ...renderSlots(self, h_, options),

                                extChildren,
                                insideFootersVN,
                                // footer

                                /* self.toWBC_(self.toWBC(loadDefaultComp))|| */
                            ]
                        );
                    }

                    if (externalWrapperObj) {
                        main = h_(
                            externalWrapperObj.comp,
                            {
                                ref: "externalHtml",
                                ...externalWrapperObj.options,
                            },
                            [main]
                        );
                    }

                    if (options?.to) {
                        main = h_("WBLink", {
                            ref: "linkHtml",
                            props: {
                                to: options?.to,
                                style_: {},
                                attrs: {},
                                html: main,
                            },
                        });
                    }
                }

                self.vNodes.main = main;
                self.vNodes.raw0 = raw0;

                if (globalFooterVN || globalHeaderVN) {
                    main = h_(
                        "div",
                        {
                            ref: "globalHtml",
                            key: el?.switch,
                        },
                        [globalHeaderVN, main, globalFooterVN]
                    );
                }

                // Menu wrapper — delegate to extracted handler
                main = applyMenuWrapper(self, h_, main, options);

    return { main, options, comp, raw0, extChildren };
}
