/**
 * Decorator: Apply development selection mode (debugger)
 */
export function applySelectMode(self, h, finalRender) {
    if (self.select === true || self.isNonEmpty(self.alertObjs)) {
        let selectItemOptions = {
            keyy: `key-${self.alertObjs.length}`,
            class: "pa-1 my-1",
            style: {
                backgroundColor: self.rColor,
                border: "10px dashed black",
            },
            attrs: {
                title: `=== WBC === \n el: ${self.nameEl} \n isVnode: ${self.isVnode(self.item_)}\n`,
            },
        };

        return h("div", selectItemOptions, [
            `${self.isVnode(self.item_) ? "VNode:" : ""}${self.nameEl}=>`,
            finalRender,
            h("VListGroup", { props: { value: !true } }, [
                h("JsonViewer", {
                    props: {
                        value: {
                            item: self.item,
                            item_: self.item_,
                            itemAccessibility: self.itemAccessibility,
                        },
                    },
                }),
            ]),
            h("VBtn", {
                props: { value: !true },
                on: { click: () => { self.select = !self.select; } },
            }, ["close"]),
        ]);
    }
    return finalRender;
}
